@startuml

class Capitan {
  -nombre: String
  -apellido: String
  -matricula: int
  +Capitan(nombre String, apellido String, matricula int): void
}

abstract class Embarcacion <<abstract>> {
  -capitan: Capitan
  -precioBase: double
  -valorAdicional: double
  -AñoDeFabricacion: int
  +montoDeAlquiler(): double
}

interface Comparable <<interface>> {
  +compareTo(o Object): int
}

class Yate {
  -cantCamarotes: int
  +compareTo(o Object): int
}

class Velero {
  -cantMastiles: int
  +esGrande(): boolean
}

Embarcacion "1" --> "1" Capitan
Yate --|> Embarcacion : extends
Velero --|> Embarcacion : extends
Yate ..|> Comparable : implements

@enduml
